package com.evolua.auth.infrastructure.persistence; import jakarta.persistence.*; import java.time.Instant; @Entity @Table(name = "auth_users") public class AuthUserEntity { @Id @GeneratedValue(strategy = GenerationType.IDENTITY) private Long id; private String userId; private String email; private String passwordHash; private String roles; private Instant createdAt; public Long getId() { return id; } public void setId(Long id) { this.id = id; } public String getUserId() { return userId; } public void setUserId(String userId) { this.userId = userId; } public String getEmail() { return email; } public void setEmail(String email) { this.email = email; } public String getPasswordHash() { return passwordHash; } public void setPasswordHash(String passwordHash) { this.passwordHash = passwordHash; } public String getRoles() { return roles; } public void setRoles(String roles) { this.roles = roles; } public Instant getCreatedAt() { return createdAt; } public void setCreatedAt(Instant createdAt) { this.createdAt = createdAt; } }
